---@class LFightEffectCtrl
local LFightEffectCtrl = LxClass("LFightEffectCtrl",nil)
-----------------------------------------------------------------
local LFightEffect = LXImport("..View.LFightEffect")

-----------------------------------------------------------------
function LFightEffectCtrl:LFightEffectCtrl(battleUnit)
	self._battleUnit = battleUnit

	---@type LFightEffect[]
	self._effectList = {}

	---@type LFightEffect[]
	self._recordHideEffectList = {}

	self._recordHurtIdMap = {}

	self._cacheList = {}
	
	self._preloadList = {}

	self._reqCntList = {}

	self._isRuning = false

	self._effectIdx = 0

	self._effTaskIdx = 0
	self._effTaskList ={}
	self._taskPreloadList ={}
	self._loadEndIndex = {}

	--- 正在播放 战斗中仅显示攻击出手者和目标者，其他场景中战斗小人隐藏
	self._showEffectFocus = false
end

function LFightEffectCtrl:Init()

end
-----------------------------------------------------------------
function LFightEffectCtrl:MakeEffectObject(parentTrans,effId,pos,dir,startTime,playTime,dissipateTime,resType)
	local eff = nil
	local curEffList = self._preloadList[effId] or {}
	local idx= nil
	if #curEffList > 0 then
		eff = curEffList[1]
		idx = eff:GetIndex()
		table.remove(curEffList, 1)
		self:SubReqCnt(effId)
	else
		idx = self._effectIdx + 1
		self._effectIdx = idx 
		eff = LFightEffect:New(self._battleUnit)	
	end
	
	eff:Create(idx,parentTrans,effId,pos,dir,startTime,playTime,dissipateTime,nil,resType)
	eff:SetBattleSkillEffect(false)
	return eff
end

function LFightEffectCtrl:MakeBattleSkillEffectObj(parentTrans,effId,pos,dir,startTime,playTime,dissipateTime,resType)
	---@type LFightEffect
	local eff = nil
	local curEffList = self._preloadList[effId] or {}
	local idx= nil
	if #curEffList > 0 then
		eff = curEffList[1]
		idx = eff:GetIndex()
		table.remove(curEffList, 1)
		self:SubReqCnt(effId)
	else
		idx = self._effectIdx + 1
		self._effectIdx = idx
		eff = LFightEffect:New(self._battleUnit)
	end

	eff:Create(idx,parentTrans,effId,pos,dir,startTime,playTime,dissipateTime,nil,resType)
	eff:SetBattleSkillEffect(true)
	return eff
end



---@return LFightEffect
function LFightEffectCtrl:PreloadEffectObject(parentTrans,effId,resType,noAddReqCnt,effData,targetObj)

	if not noAddReqCnt then
		local reqCnt = self:GetReqCnt(effId) + 1
		local preloadList = self._preloadList[effId] or {}
		local preloadCnt = #preloadList
		if preloadCnt >= reqCnt then
			return
		end

		self:AddReqCnt(effId)
	end

	local idx = self._effectIdx + 1
	self._effectIdx = idx


	--- 预加载 全屏特效
	local effType = effData and effData.effType
	if effType and effType == LSkillEffConst.PLAY_EFF_EFFECT then
		local playNum = tonumber(effData.playNum)
		if playNum == 1 then
--[[			FireEvent(EventNames.ON_LOAD_BATTLEWND_EFFECT,{
				preload = true,
				effId = effId,
				resType = resType,
				effData = effData,
				state = 0,
			})]]
			return nil,nil,true
		end
	end

	---@type LFightEffect
	local eff = LFightEffect:New(self._battleUnit)
	eff:SetEffData(effData)
	eff:SetTargetObj(targetObj)
	eff:SetBattleSkillEffect(true)
	local isSuc = eff:PreloadCreate(idx,parentTrans,effId,resType,function (...) self:OnEffPreloaded(...) end)
	self:AddPreload(eff)

	return eff,isSuc
end

---@param eff LFightEffect
function LFightEffectCtrl:AddPreload(eff)
	local effId = eff:GetEffId()
	local curEffList = self._preloadList[effId] or {}
	table.insert(curEffList, eff)
	self._preloadList[effId] = curEffList
end

function LFightEffectCtrl:AddReqCnt(effId)
	local cnt = self._reqCntList[effId] or 0
	cnt = cnt+1
	self._reqCntList[effId] =cnt

	--printErrorN("addeffid "..effId.."cnt "..cnt)
end

function LFightEffectCtrl:SubReqCnt(effId)
	local cnt = self._reqCntList[effId] or 0

	cnt = cnt -1
	cnt = Mathf.Clamp(cnt,0,cnt)
	self._reqCntList[effId] = cnt
	--printErrorN("subeffid "..effId.."cnt "..cnt)
end

function LFightEffectCtrl:GetReqCnt(effId)
	return self._reqCntList[effId] or 0
end

-----------------------------------------------------------------
function LFightEffectCtrl:AddEffect(effect)
	if(self._isRuning) then
		table.insert(self._cacheList,{true,effect})
		return
	end
	table.insert(self._effectList,effect)
end

function LFightEffectCtrl:RemoveEffect(effect)
	if(self._isRuning) then
		table.insert(self._cacheList,{false,effect})
		return
	end
	table.removeidata(self._effectList,effect)
end

function LFightEffectCtrl:DestroyEffect(effect)
	if not effect then return end
	local removeEff
	for i,v in ipairs(self._effectList) do
		if (v == effect) then
			removeEff = table.remove(self._effectList, i)
			break
		end
	end
	if removeEff then
		removeEff:Destroy()
	end
end
-----------------------------------------------------------------

function LFightEffectCtrl:OnRun(time)
	self._isRuning = true
	local delIndexList = {}
	local effectList = self._effectList

	for k ,v in ipairs(effectList) do
		if not v:OnRun(time) then

			if v:IsLongCache() then
				v:ResetToPreloaded() --重置为预加载完成的状态
				self:AddPreload(v)
			else
				v:Destroy()
			end

			table.insert(delIndexList,k)

		end
	end
	for k=#delIndexList,1,-1 do
		table.remove(effectList,delIndexList[k])
	end
	self._isRuning = false

	local cacheList = self._cacheList
	self._cacheList = {}
	for k,v in ipairs(cacheList) do
		if v[1] then
			self:AddEffect(v[2])
		else
			self:RemoveEffect(v[2])
		end
	end
end


-----------------------------------------------------------------
function LFightEffectCtrl:ClearAllEffect()
	local effList = self._effectList
	if(effList) then
		for k,v in ipairs(effList) do
			v:Destroy()
		end
	end
	self._effectList = {}

	effList = self._preloadList
	if effList then
		for k,v in pairs(effList) do
			for m,n in ipairs(v) do
				n:Destroy()
			end
		end
	end
	self._preloadList = {}
end

---预加载特效任务

function LFightEffectCtrl:PreloadEffList(effTask,atkHero)
	local idx = self._effTaskIdx or 0
	local newIdx = idx+ 1
	self._effTaskIdx = newIdx
	self._effTaskList[newIdx] = effTask
	local effList = effTask.effList
	--local isLongCache = effTask.isLongCache
	local preloadList = {}
	local effTrans = self._battleUnit:GetEffectRootTrans()
	for k,v in ipairs(effList) do
		local effRes = v.effRes --光效名字

		local resType = 1
		if v.effType == LSkillEffConst.PLAY_EFF_DRAWING then
			resType = 2
		end
		local effect,isSuc,isWndEff = self:PreloadEffectObject(effTrans, effRes,resType,true,v,atkHero)
		if effect then
			local effIndex = effect:GetIndex()
			if isSuc then
				preloadList[effIndex] = true
			end
		end

		--print(string.format("refName %s ,resIndex %s,isSuc %s ",effRes,effIndex,isSuc))
	end

	self._taskPreloadList[newIdx] = preloadList
	self:CheckTaskLoadEnd()
end

function LFightEffectCtrl:OnEffPreloaded(index)

	--print("preload loaded index "..index)
	local isFind = false
	for k,v in pairs(self._taskPreloadList) do
		if v[index] then
			v[index] = nil
			isFind = true
			break
		end
	end
	if not isFind then
		self._loadEndIndex[index] = true
		return
	end

	self:CheckTaskLoadEnd()
end

function LFightEffectCtrl:CheckTaskLoadEnd()
	for k,v in pairs(self._loadEndIndex) do
		for k1,v1 in pairs(self._taskPreloadList) do
			if v1[k] then
				v1[k] = nil
				break
			end
		end
	end

	table.removeall(self._loadEndIndex)


	for k,v in pairs(self._taskPreloadList) do
		if table.isempty(v) then
			local effTask = self._effTaskList[k]
			if effTask and effTask.endFunc then
				effTask.endFunc()
			end
			self._effTaskList[k] = nil
		end
	end
end

function LFightEffectCtrl:HidePlayingEffects(recordHurtIdMap,atkObjId)
	self._recordHurtIdMap = recordHurtIdMap
	self._showEffectFocus = true
	local recordHideEffectList = {}
	for k,v in pairs(self._effectList) do
		if not v:GetIsBattleSkill() and v:GetEffectPlayState() and
				not v:CheckIsAtkObjHitEffect(atkObjId) then
			v:SetVisible(false)
			table.insert(recordHideEffectList,v)
		end
	end
	self._recordHideEffectList = recordHideEffectList
end

function LFightEffectCtrl:ShowPlayingEffects()
	self._showEffectFocus = false
	self._recordHurtIdMap = {}
	if not self._recordHideEffectList or #self._recordHideEffectList < 1 then return end

	local rReplaceEffList = {}
	for i,v in ipairs(self._recordHideEffectList) do
		if v:GetEffectPlayState() then
			local isDead = v:CheckTargetObjDead()
			if isDead or v:CheckIsHitShowBuff() then
				v:SetVisible(false)
				if isDead and v:CheckIsBuffEffShowReplace() then
					table.insert(rReplaceEffList,v)
				end
			else
				v:SetVisible(true)
			end
		end
	end
	self._recordHideEffectList = {}
	self._rReplaceEffList = rReplaceEffList
end

function LFightEffectCtrl:ShowReplaceEffectList()
	local rReplaceEffList = self._rReplaceEffList
	if not rReplaceEffList or #rReplaceEffList < 1 then return end

	for i,v in ipairs(rReplaceEffList) do
		v:SetVisible(true)
	end
	self._rReplaceEffList = nil
end

function LFightEffectCtrl:CheckIsShowEffectFocus()
	return self._showEffectFocus
end

---@param effect LFightEffect
function LFightEffectCtrl:AddRecordHideEffectList(effect)
	if not self._recordHideEffectList then
		self._recordHideEffectList = {}
	end
	table.insert(self._recordHideEffectList,effect)
end

---@param effBattleObj LFightObject
function LFightEffectCtrl:CheckIsHurtHero(effBattleObj)
	if not self._recordHurtIdMap then return end
	return self._recordHurtIdMap[effBattleObj:GetId()] ~= nil
end

function LFightEffectCtrl:Destroy()
	self:ClearAllEffect()
	table.removeall(self)
end
-----------------------------------------------------------------
return LFightEffectCtrl